const uint8_t *font_get_glyph(char c)
{
    unsigned char uc = (unsigned char)c;
    return font_data[uc];
}

int font_text_width(const char *text)
{
    return (int)strlen(text) * FONT_WIDTH;
}

int font_text_height(void)
{
    return FONT_HEIGHT;
}
